-- Five published aptitude quizzes with explicit difficulty_level (1–5) for adaptive ordering.

-- created_by_user_id NULL so this runs without seed users (e.g. usr_parent_001).
ON CONFLICT (id) DO UPDATE SET
  slug = EXCLUDED.slug,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  is_published = EXCLUDED.is_published,
  time_per_question_seconds = EXCLUDED.time_per_question_seconds,
  default_difficulty = EXCLUDED.default_difficulty,
  updated_at = EXCLUDED.updated_at;

